import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Optionbar.css';

/**
 * Optionbar now fetches product categories and allows selecting one.
 * Props:
 *  - selectedCategory: string|null
 *  - onFilterChange: ({ type, value }) => void
 */
const Optionbar = ({ selectedCategory, onFilterChange }) => {
    const [categories, setCategories] = useState([]);

    useEffect(() => {
        const fetchCategories = async () => {
            try {
                const res = await axios.get('http://localhost:3007/api/categories', { withCredentials: true });
                setCategories(res.data);
            } catch (err) {
                console.error('Kon categories niet laden', err);
            }
        };
        fetchCategories();
    }, []);

    const handleClick = id => {
        if (id) onFilterChange({ type: 'category', value: id });
        else    onFilterChange({ type: null, value: null });
    };

    return (
        <div className="optionbar-container">
            <h3 className="optionbar-title">Filter by Category</h3>
            <div className="optionbar-scrollable">
                <ul className="optionbar-list">
                    <li
                        className={`option-item ${selectedCategory === null ? 'active' : ''}`}
                        onClick={() => handleClick(null)}
                    >
                        All Categories
                    </li>
                    {categories.map(cat => (
                        <li
                            key={cat.id_category}
                            className={`option-item ${String(selectedCategory) === String(cat.id_category) ? 'active' : ''}`}
                            onClick={() => handleClick(cat.id_category)}
                        >
                            {cat.category_name}
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
};

export default Optionbar;
